//! Integration: mesh-governed depth field → extrusion invariants (no ONNX required).

use distributed_inference::depth_extrusion::{
    extrude_depth_heightfield_rgb, extrude_depth_heightfield_rgb_weighted, DepthError,
    DepthEstimator, TriMeshRgb,
};
use distributed_inference::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};

fn z_variance(mesh: &TriMeshRgb) -> f32 {
    let zs: Vec<f32> = mesh.positions.iter().skip(2).step_by(3).copied().collect();
    if zs.is_empty() {
        return 0.0;
    }
    let m = zs.iter().sum::<f32>() / zs.len() as f32;
    zs.iter().map(|z| (z - m).powi(2)).sum::<f32>() / zs.len() as f32
}

struct ConstantPrior(Vec<f32>);

impl DepthEstimator for ConstantPrior {
    fn estimate_normalized(
        &mut self,
        rgb_f32_unit: &[f32],
        width: usize,
        height: usize,
    ) -> Result<Vec<f32>, DepthError> {
        let n = width * height;
        if rgb_f32_unit.len() != n * 3 || self.0.len() != n {
            return Err(DepthError::Shape);
        }
        Ok(self.0.clone())
    }
}

#[test]
fn synthetic_rgb_mesh_depth_then_extrude() {
    let w = 16_u32;
    let h = 16_u32;
    let mut rgb = vec![0.0_f32; (w * h * 3) as usize];
    for i in 0..(w * h) as usize {
        rgb[i * 3] = (i % 7) as f32 * 0.1;
        rgb[i * 3 + 1] = 0.35;
        rgb[i * 3 + 2] = 0.55;
    }
    let (field, prov) =
        build_mesh_depth_field(&rgb, w, h, &MeshDepthConfig::default(), None, None).unwrap();
    assert_eq!(prov.fragments.len(), 2);
    assert_eq!(field.values.len(), (w * h) as usize);

    let mesh =
        extrude_depth_heightfield_rgb(&field.values, &rgb, w as usize, h as usize, 0.2).unwrap();
    assert!(!mesh.positions.is_empty());
    assert!(mesh.indices.len() >= 6);
    for i in (2..mesh.positions.len()).step_by(3) {
        assert!(mesh.positions[i].is_finite());
    }

    let mesh_w = extrude_depth_heightfield_rgb_weighted(
        &field.values,
        &field.confidence,
        &rgb,
        w as usize,
        h as usize,
        0.2,
    )
    .unwrap();
    assert_eq!(mesh_w.indices.len(), mesh.indices.len());

    let v_full = z_variance(&mesh);
    let v_w = z_variance(&mesh_w);
    assert!(
        v_w <= v_full + 1e-6,
        "topology-gated confidence should not increase Z population variance vs full extrusion on this fixture; full={} weighted={}",
        v_full,
        v_w
    );
}

#[test]
fn stub_prior_disagreement_stresses_confidence_and_extrusion() {
    let w = 24_u32;
    let h = 24_u32;
    let n = (w * h) as usize;
    let mut rgb = vec![0.5_f32; n * 3];
    for i in 0..n {
        let x = i % w as usize;
        let y = i / w as usize;
        if (x + y) % 4 == 0 {
            rgb[i * 3] = 0.05;
            rgb[i * 3 + 1] = 0.95;
            rgb[i * 3 + 2] = 0.05;
        }
    }
    let (field_base, _) =
        build_mesh_depth_field(&rgb, w, h, &MeshDepthConfig::default(), None, None).unwrap();
    // Spatially varying third prior (reference "ONNX" shape) so raw extrusion Z variance is non-trivial.
    let mut prior_b = vec![0.0_f32; n];
    for i in 0..n {
        let y = i / w as usize;
        prior_b[i] = if (y % 2) == 0 { 0.12 } else { 0.88 };
    }
    let mut stub = ConstantPrior(prior_b.clone());
    let (field_fused, prov) = build_mesh_depth_field(
        &rgb,
        w,
        h,
        &MeshDepthConfig::default(),
        Some(&mut stub),
        None,
    )
    .unwrap();
    assert_eq!(prov.fragments.len(), 3);

    let mean_c_base: f32 = field_base.confidence.iter().copied().sum::<f32>() / n as f32;
    let mean_c_fused: f32 = field_fused.confidence.iter().copied().sum::<f32>() / n as f32;
    assert!(
        mean_c_fused < mean_c_base,
        "stub ONNX that disagrees with classical should lower mean sieve confidence"
    );

    let ex = 0.35_f32;
    let mesh_raw_onnx_like =
        extrude_depth_heightfield_rgb(&prior_b, &rgb, w as usize, h as usize, ex).unwrap();
    let mesh_weighted = extrude_depth_heightfield_rgb_weighted(
        &field_fused.values,
        &field_fused.confidence,
        &rgb,
        w as usize,
        h as usize,
        ex,
    )
    .unwrap();

    let v_raw = z_variance(&mesh_raw_onnx_like);
    let v_w = z_variance(&mesh_weighted);
    assert!(
        v_w < v_raw,
        "weighted mesh extrusion should reduce Z variance vs raw high-contrast prior when admission is down-weighted; raw={} weighted={}",
        v_raw,
        v_w
    );
}
